#include<bits/stdc++.h>
using namespace std;
long long n,k,s[21],f[21][70010];
int main()
{
    scanf("%lld%lld",&n,&k);
    int K=k;
    for(long long i=1;i<=n;i++)
    {
        f[i][1<<(i-1)]=1;
        scanf("%lld",&s[i]);
    }
    for(long long i=0;i<(1<<n);i++)
    {
        for(long long j=1;j<=n;j++)if(i&(1<<(j-1)))
        {
            for(long long k=1;k<=n;k++)if(!(i&(1<<(k-1))))
            {
                if(abs(s[j]-s[k])<=K)
                {
                    continue;
                }
                f[k][i|(1<<(k-1))]+=f[j][i];
            }
        }
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        ans+=f[i][(1<<n)-1];
    }
    printf("%lld",ans);
    return 0;
}
